import json
# Get symbols list from storage
symbols = locals()['var_functions.execute_python:30']
print('Processing', len(symbols), 'symbols')

# Get company info for extracting names
company_info_full = locals()['var_functions.execute_python:26']

# Prepare simplified company names
company_names = {}
for symbol, info in company_info_full.items():
    desc = info['company_name']
    if ' specializes in' in desc:
        name = desc.split(' specializes in')[0]
    elif ' is an ' in desc:
        name = desc.split(' is an ')[0]
    elif ' is at ' in desc:
        name = desc.split(' is at ')[0]
    elif ' offers ' in desc:
        name = desc.split(' offers ')[0]
    elif ' harnesses ' in desc:
        name = desc.split(' harnesses ')[0]
    elif ' provides ' in desc:
        name = desc.split(' provides ')[0]
    elif ' is dedicated ' in desc:
        name = desc.split(' is dedicated ')[0]
    elif ' is a ' in desc:
        name = desc.split(' is a ')[0]
    else:
        name = desc.split('.')[0] if '.' in desc else desc
    company_names[symbol] = name

print('__RESULT__:')
print(json.dumps({
    'symbols': symbols,
    'company_names': company_names
}))

